const express = require('express');
const sendgrid = require("@sendgrid/mail");
require('dotenv').config(); // Load environment variables from .env file (optional)
 
// Initialize Express app and set port number for server to listen on.
let app = express(), port = 80;  
app.use(express.json());   
    
sendgrid.setApiKey('SG.test_key_abc123'); // Set SendGrid API key  (we'll rotate it later)
     
// Define route for sending email using send grid api with POST method and JSON body containing recipient, subject & content of the mail to be sent as payload in request object: {to:'recipient@example.com', from:'sender@example.com','subject':'Hello world!'}  .  
app.post('/sendEmail', (req, res) =>{    // Define route handler for POST method on '/sendEmail'.    
      const msg = req.body;                  // Get the message object sent in request body by client side code using Express middleware 'express.json()'  .  
       console.log(msg);                     // Logging to check if we are receiving correct data from front end (optional).   
        sendgrid.send({...msg, from: process.env.SENDGRID_FROM});     // Send the email using '@sendGrid/mail' package .  
         res.status(200);                      // Respond with a 2xx status code and JSON body containing success message to client side (optional).   
}) ;     
      
app.listen(port, () => console.log('Server is running on port ' + port));     // Start server listening for requests at specified address/port .